$token = "eyJhbGciOiJIUzUxMiJ9..NxYG6JqGld_dd49ftEUGiLGenkuccFqldeOgH96qC9IMnuCAGNl_EUecJ-cVy46YlpJMwKq37Tmh2WLlM_1v6A"
$headers = @{
    "Authorization" = "Bearer $token"
}
$uri = "http://localhost:8080/api/classes?page=0&size=10&sort=className,asc"
try {
    $response = Invoke-RestMethod -Uri $uri -Method Get -Headers $headers
    $response | ConvertTo-Json -Depth 10 | Out-File "response.json"
} catch {
    $stream = $_.Exception.Response.GetResponseStream()
    $reader = New-Object IO.StreamReader($stream)
    $reader.ReadToEnd() | Out-File "response.json"
}
